+                    |payload| {
+                        Self::host_error_json(
+                            payload.code,
+                            payload.message.clone(),
+                            payload.details.clone(),
+                            payload.retryable,
+                        )
+                    },
+                );
+                return Err(error);
+            }
+
+            serde_json::to_string(&result.output).map_err(|err| {
+                Self::host_error_json(
+                    HostCallErrorCode::Internal,
+                    format!("Failed to serialize fs output: {err}"),
+                    None,
+                    None,
+                )
+            })
+        }
